import{_ as a,o as t,c as n,ae as r}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Facebook Ads Deferred Deep Linking","description":"","frontmatter":{"title":"Facebook Ads Deferred Deep Linking","slug":"facebook-ads-deferred-deep-linking"},"headers":[],"relativePath":"marketer-hub/facebook-ads-deferred-deep-linking.md","filePath":"marketer-hub/facebook-ads-deferred-deep-linking.md"}'),i={name:"marketer-hub/facebook-ads-deferred-deep-linking.md"};function o(s,e,l,d,p,c){return t(),n("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1"><strong>Overview</strong> <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;**Overview**&quot;">​</a></h2><p>Branch provides both deep linking and deferred deep linking using Facebook Ads. This article is specifically about deferred deep linking. This <strong>does not</strong> require you to integrate the Meta SDK in your app.</p><p><strong>Deferred deep linking</strong></p><p>If a user doesn’t have your app installed, you can use deferred deep linking to direct them to the app store. Once they install the app, they will be taken to specific, relevant content inside your mobile app immediately.</p><p>This solves the problem of new users being sent to generic app home screens after they click an ad. Instead of landing on the home screen, the user is seamlessly taken to the exact product, content, or page they were expecting to see.</p><h2 id="prerequisites" tabindex="-1"><strong>Prerequisites</strong> <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;**Prerequisites**&quot;">​</a></h2><p>To use deferred deep linking with Facebook Ads, you must first:</p><ol><li><p>Enable Branch Ads for your Branch account. Please contact your Account Manager or <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">our Sales team</a> to learn more about pricing and availability.</p></li><li><p>Integrate the Branch SDK into your mobile app(s):</p><ol><li><a href="https://help.branch.io/developers-hub/docs/ios-basic-integration" target="_blank" rel="noreferrer">iOS</a></li><li><a href="https://help.branch.io/developers-hub/docs/android-basic-integration" target="_blank" rel="noreferrer">Android</a></li></ol></li><li><p>Configure <a href="https://help.branch.io/developers-hub/docs/ios-universal-links" target="_blank" rel="noreferrer">Universal Links</a> and/or <a href="https://help.branch.io/developers-hub/docs/android-app-links" target="_blank" rel="noreferrer">App Links</a>.</p></li><li><p>Implement deep link handling for your app:</p><ol><li><a href="https://help.branch.io/developers-hub/docs/ios-advanced-features#general-deep-linking" target="_blank" rel="noreferrer">iOS</a></li><li><a href="https://help.branch.io/developers-hub/docs/android-advanced-features#general-deep-linking" target="_blank" rel="noreferrer">Android</a></li></ol></li><li><p>Have admin access to your Facebook Ads account.</p></li><li><p>Integrate Facebook Ads as an ad partner in Branch using our <a href="./ad-partner-integration-guide.html">Ad Partner Integration Guide</a> and the <a href="./facebook-ads-overview.html#event-names">event mapping table</a> between Branch and Facebook.</p></li><li><p>Use a <a href="./ad-links-index.html">Branch Ad Link</a> in your Facebook Ads advertising campaign.</p></li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>Unlike other Self-Attributing Networks where Branch can retrieve data directly from the SAN partner without a Branch Link, Facebook&#39;s deferred deep linking implementation requires a Branch Ad Link because it relies on a passive deep view from a browser. This enables Branch to gather web session metadata.</p></div><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>For deep linking and deferred deep linking with Facebook Ads, you can use Instant Experience Templates from Meta. Then, when a user clicks on an ad, the following happens:</p><ol><li>A <a href="./ad-links.html">Branch Ad Link</a> is activated in the Facebook Ads campaign.</li><li>A <a href="./deepviews.html">Branch Deepview</a> opens a webpage.</li><li>Branch gathers all the metadata linked to that web session.</li><li>The Branch Deepview directs users to the Apple App Store or Google Play Store for app installation.</li><li>The user installs and launches the app.</li><li>Branch <a href="./predictive-modeling.html">probabilistically</a> associates that user session with the web session.</li><li>Branch sends the link data in the callback to facilitate deep link navigation.</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>The <strong>Leave Facebook</strong> modal is presented by Facebook when the user leaves the in-app browser from paid media. This is not a URL scheme modal and it <strong>cannot</strong> be bypassed.</p></div><h2 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h2><p>To use deferred deep linking in your Facebook Ads campaign:</p><ol><li><p>Create a <a href="./ad-links.html">Branch Ad Link</a>, and make sure to append <code>$deeplink_no_attribution=true</code> at the end.</p><ol><li>This parameter disables Branch&#39;s deep link attribution and allows Facebook to attribute installs through their own conversion logic, which Branch then analyzes.</li></ol></li><li><p>Create an ad campaign in Facebook Ads.</p></li><li><p>In the <strong>Destination</strong> settings for the ad, select the <strong>Instant Experience</strong> option.<br><em>[Image: Integration between Branch and Facebook Ads using Instant Experience destination for deferred deep linking.]</em>.png)</p></li><li><p>Select <strong>Create New</strong> to create a <strong>Custom Instant Experience</strong>.</p></li><li><p>Add relevant components to your ad on the <strong>Select components to add</strong> screen, such as buttons, creatives, or content.</p></li><li><p>Within the <strong>Button</strong> component settings, set the <strong>Destination</strong> as <strong>Website</strong> and place your Branch Ad Link in that field.</p></li></ol>',16)])])}const b=a(i,[["render",o]]);export{g as __pageData,b as default};
